                if (!visited[j] && (arr[i] & arr[j]) === k) {
                    // Swap the elements
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                    visited[i] = true;
                    visited[j] = true;
                    break;
                }
                j++;
            }
        }

        // Check if the array is sorted
        let isSorted = true;
        for (let i = 0; i < n - 1; i++) {
            if (arr[i] > arr[i + 1]) {
                isSorted = false;
                break;
            }
        }

        if (isSorted) {
            return k;
        }
    }

    return 0;
}

